#include <iostream>
#include <string>
#include <iomanip>

int main() {
    BankAccount myAccount(150.0);
    std::cout << "Initial: " << std::fixed << std::setprecision(2) << myAccount.getBalance() << std::endl;

    myAccount.deposit(75.0); // Return value ignored
    std::cout << "After deposit: " << myAccount.getBalance() << std::endl;

    myAccount.withdraw(200.0); // Return value ignored, will fail
    std::cout << "After failed withdraw: " << myAccount.getBalance() << std::endl;

    myAccount.withdraw(50.0); // Return value ignored, will succeed
    std::cout << "After successful withdraw: " << myAccount.getBalance() << std::endl;

    myAccount.deposit(-10.0); // Return value ignored, will fail
    myAccount.withdraw(-20.0); // Return value ignored, will fail

    std::cout << "Final: " << myAccount.getBalance() << std::endl;

    return 0;
}
